// ═══════════════════════════════════════════════════════
// Step 12: Report-Tabelle erstellen
// Erzeugt eine strukturierte Tabelle mit allen Ergebnissen
// fuer die Anzeige in n8n und fuer den Export
// ═══════════════════════════════════════════════════════
const data = $input.item.json;
const config = data.config;
const einzelvergleiche = data.einzelvergleiche || [];

// --- Tabellen-Zeilen als Array of Objects (fuer n8n Table View) ---
const reportTable = einzelvergleiche.map(e => ({
  Nr: e.id,
  Kategorie: e.kategorie,
  Aspekt: e.aspekt,
  [config.ownCompanyShort]: e.own_data,
  [`${config.competitorShort} (RAG)`]: (e.vergleich_aus_rag || '').substring(0, 300) + ((e.vergleich_aus_rag || '').length > 300 ? '...' : ''),
  [`${config.competitorShort} (Benchmark)`]: e.benchmark_competitor,
  Bewertung: e.bewertung || 'nicht ermittelt',
  RAG_Chunks: e.ragChunkCount,
  RAG_Distances: (e.ragDistances || []).join(', '),
  Tokens: e.tokens
}));

// --- Zusammenfassung ---
const ownBetter = einzelvergleiche.filter(e => (e.bewertung || '').toLowerCase().includes(config.ownCompanyShort.toLowerCase() + ' besser')).length;
const compBetter = einzelvergleiche.filter(e => (e.bewertung || '').toLowerCase().includes(config.competitorShort.toLowerCase() + ' besser')).length;
const equal = einzelvergleiche.filter(e => (e.bewertung || '').toLowerCase().includes('gleichwertig')).length;
const unclear = einzelvergleiche.length - ownBetter - compBetter - equal;

return {
  reportTable: reportTable,
  summary: {
    totalFacts: einzelvergleiche.length,
    ownBetter: ownBetter,
    competitorBetter: compBetter,
    equal: equal,
    unclear: unclear,
    ownCompany: config.ownCompanyName,
    competitor: config.competitorName
  },
  gesamtvergleich: data.gesamtvergleich,
  config: config,
  meta: {
    model: data.model,
    usage: data.usage,
    timestamp: data.timestamp,
    status: data.status
  }
};
